const items = $input.all();
const grouped = {};
for (const item of items) {
  const { user_id, debt_name, due_date, kind } = item.json;
  if (!grouped[user_id]) grouped[user_id] = [];
  grouped[user_id].push({ debt_name, due_date, kind });
}
const lines = Object.entries(grouped).map(([uid, debts]) =>
  debts.map(d => `• ${d.kind === 'debt' ? '💸' : '💰'} *${d.debt_name}* — ${d.due_date} (user: ${uid.slice(0,8)}...)`).join('\n')
).join('\n');
return [{ json: { lines, count: items.length } }];
